function getCurrentLang() {
    return localStorage.getItem('nova_lang') || 'en';
}

function t(key) {
    const lang = getCurrentLang();
    return (TRANSLATIONS[lang] && TRANSLATIONS[lang][key]) || (TRANSLATIONS['en'] && TRANSLATIONS['en'][key]) || key;
}

function setLang(lang) {
    localStorage.setItem('nova_lang', lang);
    document.cookie = 'nova_lang=' + encodeURIComponent(lang) + '; path=/; max-age=' + (365 * 24 * 60 * 60);
    location.reload();
}

function toggleLang() {
    const current = getCurrentLang();
    setLang(current === 'en' ? 'my' : 'en');
}

/* ── MyMemory API translation ─────────────────────────────── */

const TRANSLATION_CACHE_KEY = 'nova_api_translations';

function getTranslationCache() {
    try {
        return JSON.parse(localStorage.getItem(TRANSLATION_CACHE_KEY)) || {};
    } catch {
        return {};
    }
}

function saveTranslationCache(cache) {
    localStorage.setItem(TRANSLATION_CACHE_KEY, JSON.stringify(cache));
}

async function apiTranslate(text, from = 'en', to = 'my') {
    if (!text || !text.trim()) return text;

    const cache = getTranslationCache();
    const cacheKey = from + '|' + to + '|' + text;
    if (cache[cacheKey]) return cache[cacheKey];

    try {
        const url = '/Nova_News/includes/translate.php?' + new URLSearchParams({ text, from, to });
        const res = await fetch(url);
        if (!res.ok) return text;

        const data = await res.json();
        const translated = data.translatedText || text;

        cache[cacheKey] = translated;
        if (Object.keys(cache).length > 500) {
            const keys = Object.keys(cache);
            for (let i = 0; i < 100; i++) delete cache[keys[i]];
        }
        saveTranslationCache(cache);

        return translated;
    } catch {
        return text;
    }
}

async function translatePageContent() {
    const lang = getCurrentLang();
    if (lang === 'en') return;

    const SKIP_TAGS = new Set([
        'SCRIPT', 'STYLE', 'LINK', 'META', 'INPUT', 'TEXTAREA',
        'SELECT', 'BUTTON', 'FORM', 'CODE', 'PRE', 'SVG', 'CANVAS',
        'NOSCRIPT', 'IFRAME', 'OBJECT', 'EMBED',
    ]);

    const SKIP_CLASSES = new Set([
        'blink-text', 'ticker-track', 'fa-solid', 'fa-moon', 'fa-sun',
        'fa-magnifying-glass', 'fa-bolt', 'fa-credit-card',
    ]);

    const textNodes = [];
    const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT, {
        acceptNode(node) {
            const parent = node.parentElement;
            if (!parent) return NodeFilter.FILTER_REJECT;
            if (SKIP_TAGS.has(parent.tagName)) return NodeFilter.FILTER_REJECT;
            if (parent.closest('script, style, select, [data-no-translate]')) return NodeFilter.FILTER_REJECT;
            if ([...parent.classList].some(c => SKIP_CLASSES.has(c))) return NodeFilter.FILTER_REJECT;
            if (parent.closest('[role="search"], [role="navigation"]')) return NodeFilter.FILTER_REJECT;
            if (!node.textContent.trim()) return NodeFilter.FILTER_REJECT;
            return NodeFilter.FILTER_ACCEPT;
        }
    });

    let node;
    while ((node = walker.nextNode())) {
        textNodes.push(node);
    }

    const BATCH_SIZE = 5;
    for (let i = 0; i < textNodes.length; i += BATCH_SIZE) {
        const batch = textNodes.slice(i, i + BATCH_SIZE);
        await Promise.all(batch.map(async (node) => {
            const original = node.textContent.trim();
            if (!original) return;
            node.textContent = await apiTranslate(original, 'en', lang);
        }));
    }
}

/* ── Auto-translate dynamic content on page load ──────────── */
document.addEventListener('DOMContentLoaded', () => {
    if (getCurrentLang() === 'my') {
        translatePageContent();
    }
});
